// Filter articles from the last 24 hours and focus on automation
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const automationKeywords = [
  'automation', 'ai', 'artificial intelligence', 'machine learning',
  'workflow', 'bot', 'chatbot', 'rpa', 'robotic process automation',
  'zapier', 'n8n', 'make', 'integromat', 'api', 'integration',
  'no-code', 'low-code', 'pipeline', 'trigger', 'webhook'
];

const filteredArticles = [];

for (const item of $input.all()) {
  const pubDate = new Date(item.json.pubDate || item.json.isoDate);

  // Check if article is from the last 24 hours
  if (pubDate >= yesterday) {
    const title = (item.json.title || '').toLowerCase();
    const description = (item.json.description || item.json.content || '').toLowerCase();
    const fullText = title + ' ' + description;

    // Check if article contains automation-related keywords
    const hasAutomationKeywords = automationKeywords.some(keyword => 
      fullText.includes(keyword.toLowerCase())
    );

    if (hasAutomationKeywords) {
      filteredArticles.push({
        json: {
          title: item.json.title,
          link: item.json.link,
          description: item.json.description || item.json.content,
          pubDate: item.json.pubDate || item.json.isoDate,
          source: item.json.meta?.title || 'Unknown'
        }
      });
    }
  }
}

return filteredArticles;

// Prepare articles for AI summarization
const articles = $input.all();

if (articles.length === 0) {
  return [{ json: { hasArticles: false, message: 'No recent AI automation news found today.' } }];
}

// Limit to top 10 most recent articles
const sortedArticles = articles
  .sort((a, b) => new Date(b.json.pubDate) - new Date(a.json.pubDate))
  .slice(0, 10);

const articlesText = sortedArticles.map((article, index) => {
  return `${index + 1}. **${article.json.title}**\n   Source: ${article.json.source}\n   Link: ${article.json.link}\n   Description: ${article.json.description?.substring(0, 200)}...\n`;
}).join('\n');

return [{
  json: {
    hasArticles: true,
    articlesCount: sortedArticles.length,
    articlesText: articlesText,
    articles: sortedArticles
  }
}];
